sys_atf_test_step.step:
(function step(assert, $library) {
    // Test Capability Taxonomy Map CRUD operations
    // Create
    var gr = new GlideRecord('u_capability_taxonomy_map');
    gr.initialize();
    gr.u_capability = 'AI Orchestration';
    gr.u_taxonomy = 'DevOps';
    var id = gr.insert();
    assert.isTrue(id, 'Capability taxonomy map should be created');

    // Read
    gr = new GlideRecord('u_capability_taxonomy_map');
    gr.get(id);
    assert.isTrue(gr.isValid(), 'Capability taxonomy map should exist');

    // Update
    gr.u_taxonomy = 'CI/CD';
    gr.update();

    // Delete
    gr.deleteRecord();

    // Verify deletion
    gr = new GlideRecord('u_capability_taxonomy_map');
    gr.get(id);
    assert.isFalse(gr.isValid(), 'Capability taxonomy map should be deleted');
})(step, $library);
